SELECT management_packs.name AS ManagementPackName, workflows.display_name AS WorkflowDisplayName, workflows.created_at AS WorkflowCreationTime
FROM workflows
INNER JOIN management_packs ON workflows.management_pack_id = management_packs.management_pack_id;

SELECT COUNT(DISTINCT w.workflow_id) AS total_note_workflows
FROM workflows w
JOIN notes n ON w.workflow_id = n.workflow_id;

SELECT workflow_id 
FROM workflows
WHERE is_active = 0;

SELECT log_id, workflow_id, log_message, log_level
FROM workflow_logs
WHERE log_level = 'ERROR' AND DATE(log_timestamp) > DATE('now', '-30 days');

SELECT COUNT(*)
FROM management_packs
WHERE is_active = 1 AND last_updated >= '2023-01-01';

SELECT name, description, version, is_active
FROM management_packs
WHERE is_active = 1;

SELECT COUNT(*)
FROM workflows
WHERE is_active = 1;

SELECT COUNT(*)
FROM management_packs
WHERE management_pack_id > 5 AND is_active = 1;

SELECT COUNT(*) 
FROM workflow_environments 
WHERE environment_id = 1 AND value = 'ON';

SELECT workflow_id, environment_id, log_level, COUNT(*) AS num_logs
FROM workflow_logs
GROUP BY workflow_id, environment_id, log_level;

SELECT display_name
FROM workflows
WHERE is_active = (SELECT is_active FROM workflows WHERE display_name = 'Workflow 0');

SELECT COUNT(environment_id) 
FROM workflow_environments 
WHERE workflow_id = 0;

SELECT T1.workflow_id, T2.value
FROM override_parameters AS T1
JOIN override_parameter_values AS T2 ON T1.override_parameter_id = T2.override_parameter_id;

SELECT log_message, log_level, log_timestamp
FROM workflow_logs
WHERE workflow_id = 0 AND environment_id = 1;
